import{_ as s,c as n,o as a,a2 as o}from"./chunks/framework.aRVg8jgk.js";const y=JSON.parse('{"title":"Monitoring & Observability","description":"Set up Prometheus metrics, Grafana dashboards, and structured logging for Lynq. Includes metrics catalog, events reference, and alerting overview.","frontmatter":{"description":"Set up Prometheus metrics, Grafana dashboards, and structured logging for Lynq. Includes metrics catalog, events reference, and alerting overview."},"headers":[],"relativePath":"monitoring.md","filePath":"monitoring.md","lastUpdated":1779353865000}'),t={name:"monitoring.md"};function l(r,e,d,p,c,i){return a(),n("div",null,[...e[0]||(e[0]=[o(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /monitoring.md for this page in Markdown format</div><h1 id="monitoring-observability" tabindex="-1">Monitoring &amp; Observability <a class="header-anchor" href="#monitoring-observability" aria-label="Permalink to &quot;Monitoring &amp; Observability&quot;">​</a></h1><p>Lynq exposes 15 Prometheus metrics at <code>:8443/metrics</code>, emits structured Kubernetes events per reconciliation, and ships a pre-built Grafana dashboard.</p><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><h3 id="prometheus" tabindex="-1">Prometheus <a class="header-anchor" href="#prometheus" aria-label="Permalink to &quot;Prometheus&quot;">​</a></h3><p><strong>Enable ServiceMonitor</strong> (requires Prometheus Operator): uncomment the prometheus section in <code>config/default/kustomization.yaml</code>:</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#E1E4E8;">- </span><span style="color:#9ECBFF;">../prometheus</span><span style="color:#6A737D;">   # uncomment this line</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Then redeploy:</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> apply</span><span style="color:#79B8FF;"> -k</span><span style="color:#9ECBFF;"> config/default</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>Manual scrape config:</strong></p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># prometheus.yml</span></span>
<span class="line"><span style="color:#85E89D;">scrape_configs</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">- </span><span style="color:#85E89D;">job_name</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">lynq</span></span>
<span class="line"><span style="color:#85E89D;">  kubernetes_sd_configs</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">role</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">pod</span></span>
<span class="line"><span style="color:#85E89D;">    namespaces</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">      names</span><span style="color:#E1E4E8;">: [</span><span style="color:#9ECBFF;">lynq-system</span><span style="color:#E1E4E8;">]</span></span>
<span class="line"><span style="color:#85E89D;">  relabel_configs</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">source_labels</span><span style="color:#E1E4E8;">: [</span><span style="color:#9ECBFF;">__meta_kubernetes_pod_label_control_plane</span><span style="color:#E1E4E8;">]</span></span>
<span class="line"><span style="color:#85E89D;">    action</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">keep</span></span>
<span class="line"><span style="color:#85E89D;">    regex</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">controller-manager</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">source_labels</span><span style="color:#E1E4E8;">: [</span><span style="color:#9ECBFF;">__meta_kubernetes_pod_container_port_name</span><span style="color:#E1E4E8;">]</span></span>
<span class="line"><span style="color:#85E89D;">    action</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">keep</span></span>
<span class="line"><span style="color:#85E89D;">    regex</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">https</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p><strong>Test the endpoint:</strong></p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> port-forward</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#9ECBFF;"> deployment/lynq-controller-manager</span><span style="color:#9ECBFF;"> 8443:8443</span></span>
<span class="line"><span style="color:#B392F0;">curl</span><span style="color:#79B8FF;"> -k</span><span style="color:#9ECBFF;"> https://localhost:8443/metrics</span><span style="color:#F97583;"> |</span><span style="color:#B392F0;"> grep</span><span style="color:#9ECBFF;"> lynqnode_</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>Troubleshoot no metrics data:</strong></p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># Check flag is set</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> get</span><span style="color:#9ECBFF;"> deployment</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#9ECBFF;"> lynq-controller-manager</span><span style="color:#79B8FF;"> -o</span><span style="color:#9ECBFF;"> yaml</span><span style="color:#F97583;"> |</span><span style="color:#B392F0;"> grep</span><span style="color:#9ECBFF;"> metrics-bind-address</span></span>
<span class="line"><span style="color:#6A737D;"># Should show: --metrics-bind-address=:8443 (not &quot;0&quot;)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># Check service exists</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> get</span><span style="color:#9ECBFF;"> svc</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#9ECBFF;"> lynq-controller-manager-metrics-service</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># Check ServiceMonitor (if using prometheus-operator)</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> get</span><span style="color:#9ECBFF;"> servicemonitor</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h3 id="grafana-dashboard" tabindex="-1">Grafana Dashboard <a class="header-anchor" href="#grafana-dashboard" aria-label="Permalink to &quot;Grafana Dashboard&quot;">​</a></h3><p>Import <code>config/monitoring/grafana-dashboard.json</code> via <strong>Dashboards → Import</strong> in the Grafana UI. Select your Prometheus datasource. The dashboard ships 17 panels grouped into four categories:</p><ul><li><strong>Top-line stat panels</strong>: Total Desired / Ready / Failed Nodes, Total Conflicted Resources</li><li><strong>Reconciliation health</strong>: Reconciliation Duration percentiles, Reconciliation Rate, Error Rate, LynqNode Ready Status, Degraded Nodes</li><li><strong>Resource &amp; conflict breakdowns</strong>: Resource Counts by Node and Total, Conflicted Resources by Node and Total, Conflicts Rate by Node</li><li><strong>Hub &amp; runtime internals</strong>: Hub Health, Apply Rate by Kind, Work Queue Depth</li></ul><h2 id="metrics-catalog" tabindex="-1">Metrics Catalog <a class="header-anchor" href="#metrics-catalog" aria-label="Permalink to &quot;Metrics Catalog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Metric</th><th>Type</th><th>Labels</th><th>Description</th></tr></thead><tbody><tr><td><code>lynqnode_reconcile_duration_seconds</code></td><td>Histogram</td><td><code>result</code></td><td>LynqNode reconciliation latency</td></tr><tr><td><code>lynqnode_resources_desired</code></td><td>Gauge</td><td><code>lynqnode</code>, <code>namespace</code></td><td>Desired resource count per node</td></tr><tr><td><code>lynqnode_resources_ready</code></td><td>Gauge</td><td><code>lynqnode</code>, <code>namespace</code></td><td>Ready resource count per node</td></tr><tr><td><code>lynqnode_resources_failed</code></td><td>Gauge</td><td><code>lynqnode</code>, <code>namespace</code></td><td>Failed resource count per node</td></tr><tr><td><code>lynqnode_resources_conflicted</code></td><td>Gauge</td><td><code>lynqnode</code>, <code>namespace</code></td><td>Resources in conflict state</td></tr><tr><td><code>lynqnode_conflicts_total</code></td><td>Counter</td><td><code>lynqnode</code>, <code>namespace</code>, <code>resource_kind</code>, <code>conflict_policy</code></td><td>Total conflicts detected</td></tr><tr><td><code>lynqnode_condition_status</code></td><td>Gauge</td><td><code>lynqnode</code>, <code>namespace</code>, <code>type</code></td><td>Condition status (0=False, 1=True, 2=Unknown)</td></tr><tr><td><code>lynqnode_degraded_status</code></td><td>Gauge</td><td><code>lynqnode</code>, <code>namespace</code>, <code>reason</code></td><td>Degraded status (0=healthy, 1=degraded)</td></tr><tr><td><code>hub_desired</code></td><td>Gauge</td><td><code>hub</code>, <code>namespace</code></td><td>Desired LynqNode count for a hub</td></tr><tr><td><code>hub_ready</code></td><td>Gauge</td><td><code>hub</code>, <code>namespace</code></td><td>Ready LynqNode count</td></tr><tr><td><code>hub_failed</code></td><td>Gauge</td><td><code>hub</code>, <code>namespace</code></td><td>Failed LynqNode count</td></tr><tr><td><code>apply_attempts_total</code></td><td>Counter</td><td><code>kind</code>, <code>result</code>, <code>conflict_policy</code></td><td>Resource apply attempts</td></tr><tr><td><code>lynqform_rollout_updating_nodes</code></td><td>Gauge</td><td><code>form</code>, <code>namespace</code></td><td>Nodes currently being updated (v1.1.16+)</td></tr><tr><td><code>lynqform_rollout_phase</code></td><td>Gauge</td><td><code>form</code>, <code>namespace</code></td><td>Rollout phase: 0=Idle, 1=InProgress, 2=Failed, 3=Complete (v1.1.16+)</td></tr><tr><td><code>lynqform_rollout_progress</code></td><td>Gauge</td><td><code>form</code>, <code>namespace</code></td><td>Rollout progress percentage (v1.1.16+)</td></tr></tbody></table><p>For PromQL queries using these metrics, see <a href="./prometheus-queries">Prometheus Query Examples</a>.</p><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to &quot;Events&quot;">​</a></h2><p>Kubernetes events are emitted for key lifecycle transitions.</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># Events for a specific node</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> describe</span><span style="color:#9ECBFF;"> lynqnode</span><span style="color:#F97583;"> &lt;</span><span style="color:#9ECBFF;">nam</span><span style="color:#E1E4E8;">e</span><span style="color:#F97583;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># All LynqNode events</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> get</span><span style="color:#9ECBFF;"> events</span><span style="color:#79B8FF;"> -A</span><span style="color:#79B8FF;"> --field-selector</span><span style="color:#9ECBFF;"> involvedObject.kind=LynqNode</span><span style="color:#79B8FF;"> --sort-by=</span><span style="color:#9ECBFF;">&#39;.lastTimestamp&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><table tabindex="0"><thead><tr><th>Event</th><th>Type</th><th>Meaning</th></tr></thead><tbody><tr><td><code>TemplateApplied</code></td><td>Normal</td><td>Resources applied successfully</td></tr><tr><td><code>LynqNodeDeleting</code></td><td>Normal</td><td>Node deletion started</td></tr><tr><td><code>LynqNodeDeleted</code></td><td>Normal</td><td>Node deletion completed</td></tr><tr><td><code>TemplateRenderError</code></td><td>Warning</td><td>Template syntax or variable error</td></tr><tr><td><code>ApplyFailed</code></td><td>Warning</td><td>Resource apply failed (RBAC, quota, etc.)</td></tr><tr><td><code>ResourceConflict</code></td><td>Warning</td><td>SSA field-manager conflict detected</td></tr><tr><td><code>ForceApply</code></td><td>Warning</td><td>Ownership taken with <code>conflictPolicy: Force</code></td></tr><tr><td><code>DependencySkipped</code></td><td>Warning</td><td>Resource skipped — dependency failed</td></tr><tr><td><code>ReadinessTimeout</code></td><td>Warning</td><td>Resource did not become ready in time</td></tr><tr><td><code>DependencyError</code></td><td>Warning</td><td>Dependency cycle detected</td></tr><tr><td><code>LynqNodeDeletionFailed</code></td><td>Warning</td><td>Node cleanup failed</td></tr></tbody></table><h2 id="logging" tabindex="-1">Logging <a class="header-anchor" href="#logging" aria-label="Permalink to &quot;Logging&quot;">​</a></h2><p>Configure log level via the <code>--zap-log-level</code> flag: <code>debug</code>, <code>info</code> (default), <code>error</code>.</p><p>All logs are structured JSON:</p><div class="language-json line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#E1E4E8;">{</span><span style="color:#79B8FF;">&quot;level&quot;</span><span style="color:#E1E4E8;">:</span><span style="color:#9ECBFF;">&quot;info&quot;</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">&quot;ts&quot;</span><span style="color:#E1E4E8;">:</span><span style="color:#9ECBFF;">&quot;2025-01-15T10:30:00Z&quot;</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">&quot;msg&quot;</span><span style="color:#E1E4E8;">:</span><span style="color:#9ECBFF;">&quot;Reconciliation completed&quot;</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">&quot;lynqnode&quot;</span><span style="color:#E1E4E8;">:</span><span style="color:#9ECBFF;">&quot;acme-web&quot;</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">&quot;ready&quot;</span><span style="color:#E1E4E8;">:</span><span style="color:#79B8FF;">10</span><span style="color:#E1E4E8;">,</span><span style="color:#79B8FF;">&quot;failed&quot;</span><span style="color:#E1E4E8;">:</span><span style="color:#79B8FF;">0</span><span style="color:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># Follow all logs</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> logs</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#9ECBFF;"> deployment/lynq-controller-manager</span><span style="color:#79B8FF;"> -f</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># Errors only</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> logs</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#9ECBFF;"> deployment/lynq-controller-manager</span><span style="color:#F97583;"> |</span><span style="color:#B392F0;"> grep</span><span style="color:#9ECBFF;"> &#39;&quot;level&quot;:&quot;error&quot;&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;"># Specific node</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> logs</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span><span style="color:#9ECBFF;"> deployment/lynq-controller-manager</span><span style="color:#F97583;"> |</span><span style="color:#B392F0;"> grep</span><span style="color:#9ECBFF;"> &quot;acme-web&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="alerting" tabindex="-1">Alerting <a class="header-anchor" href="#alerting" aria-label="Permalink to &quot;Alerting&quot;">​</a></h2><p>Alert rules are in <code>config/prometheus/alerts.yaml</code>. Deploy with:</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> apply</span><span style="color:#79B8FF;"> -f</span><span style="color:#9ECBFF;"> config/prometheus/alerts.yaml</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><table tabindex="0"><thead><tr><th>Severity</th><th>Alerts</th></tr></thead><tbody><tr><td>Critical</td><td><code>LynqNodeDegraded</code>, <code>LynqNodeResourcesFailed</code>, <code>LynqNodeNotReady</code>, <code>LynqNodeStatusUnknown</code>, <code>HubManyNodesFailure</code></td></tr><tr><td>Warning</td><td><code>LynqNodeResourcesMismatch</code>, <code>LynqNodeResourcesConflicted</code>, <code>LynqNodeHighConflictRate</code>, <code>HubNodesFailure</code>, <code>HubDesiredCountMismatch</code>, <code>LynqNodeReconciliationErrors</code>, <code>LynqNodeReconciliationSlow</code>, <code>HighApplyFailureRate</code></td></tr><tr><td>Info</td><td><code>LynqNodeNewConflictsDetected</code></td></tr></tbody></table><p>For per-alert diagnosis and resolution steps, see <a href="./alert-runbooks">Alert Runbooks</a>.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./prometheus-queries">Prometheus Query Examples</a> — PromQL cookbook (50+ queries)</li><li><a href="./alert-runbooks">Alert Runbooks</a> — per-alert diagnosis and resolution</li><li><a href="./troubleshooting">Troubleshooting</a> — symptom-based diagnosis</li><li><a href="./performance">Performance</a> — scaling and optimization</li></ul>`,37)])])}const b=s(t,[["render",l]]);export{y as __pageData,b as default};
